import { Link, useNavigate } from "react-router-dom";

function Sidebar() {
    const navigate = useNavigate();
    const token = localStorage.getItem("token");

    const logout = () => {
        localStorage.removeItem("token");
        localStorage.removeItem("role");
        navigate("/");
    };

    if (!token) return null;

    return (
        <div className="d-flex flex-column flex-shrink-0 p-3 bg-dark text-white vh-100" style={{ width: "220px" }}>
            <h3 className="text-center mb-4">CRM Panel</h3>
            <ul className="nav nav-pills flex-column mb-auto">
                <li className="nav-item">
                    <Link to="/dashboard" className="nav-link text-white" aria-current="page">
                        <i className="bi bi-speedometer2 me-2"></i> Dashboard
                    </Link>
                </li>
                <li>
                    <Link to="/leads" className="nav-link text-white">
                        <i className="bi bi-people me-2"></i> Leads
                    </Link>
                </li>
            </ul>
            <hr />
            <button
                onClick={logout}
                className="btn btn-outline-light w-100"
            >
                <i className="bi bi-box-arrow-right me-2"></i> Logout
            </button>
        </div>
    );
}

export default Sidebar;
